RT，今天周赛的结果简直是最正常的一集。主要是A-D图论BFS，E-G概率与期望。 题解A. 最小表示法 给定一个非空的字符串 $S$，只包含英文小写字母。 将 $S$ 第一个字符移到末尾的操作称为循环左移。 你可以将输入的字符串 $S$ 循环左移任意多的次数，请你输出通过这种方法获得的字典序最小和最大的字符串。 $S$ 的长度不超过 1000。 非常简单，不多说了放代码。 123456789101112131415161718192021222324252627#include&lt;bits/stdc++.h&gt;using namespace std;string s; string ans[1005];int n;int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;s; n=s.size(); ans[0]=s; s+=s; for(int i=1;i&lt;n;i++) { ans[i]=s.substr(i,n); } sort(ans,ans+n); cout&lt;&lt;ans[0]&lt;&lt;&quot;
&quot;&lt;&lt;ans[n-1]&lt;&lt;&quot;
&quot;; return 0;} B. 树上奇偶路径 给出一棵 $n$ 个点 $n-1$ 条边的树，其中第 $i$ 条边连接点 $a_i$ 和点 $b_i$ 。 给出 $Q$ 个询问。第 $i$ 个询问给出两个点，$c_i$ 和 $d_i$ 。 若 $c_i$ 和 $d_i$ 之间的路径的边数为奇数，输出Road，若为偶数则输出Town。 用一个bool数组存一下每个点的深度，奇深度，偶深度分别为 $0$，$1$ （顺序不影响），然后跑一遍BFS即可。 1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556575859606162636465#include&lt;bits/stdc++.h&gt;using namespace std;int n,q;bool vis[100005];vector&lt;int&gt; e[100005];bool ans[100005];void bfs(int s){ queue&lt;int&gt; q; vis[s]=1; ans[1]=1; q.push(1); while(!q.empty()) { int u=q.front(); q.pop(); for(int i=0;i&lt;e[u].size();i++) { int v=e[u][i]; if(vis[v]) { continue; } vis[v]=1; ans[v]=!ans[u]; q.push(v); } }}int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;n&gt;&gt;q; for(int i=1;i&lt;n;i++) { int a,b; cin&gt;&gt;a&gt;&gt;b; e[a].push_back(b); e[b].push_back(a); } bfs(1); while(q--) { int c,d; cin&gt;&gt;c&gt;&gt;d; if(ans[c]==ans[d]) { cout&lt;&lt;&quot;Town
&quot;; } else { cout&lt;&lt;&quot;Road
&quot;; } } return 0;} C. 是合法的BFS序吗？ The BFS algorithm is defined as follows. Consider an undirected graph with vertices numbered from $ 1 $ to $ n $ . Initialize $ q $ as a new queue containing only vertex $ 1 $ , mark the vertex $ 1 $ as used. Extract a vertex $ v $ from the head of the queue $ q $ . Print the index of vertex $ v $ . Iterate in arbitrary order through all such vertices $ u $ that $ u $ is a neighbor of $ v $ and is not marked yet as used. Mark the vertex $ u $ as used and insert it into the tail of the queue $ q $ . If the queue is not empty, continue from step 2. Otherwise finish. Since the order of choosing neighbors of each vertex can vary, it turns out that there may be multiple sequences which BFS can print. In this problem you need to check whether a given sequence corresponds to some valid BFS traversal of the given tree starting from vertex $ 1 $ . The tree is an undirected graph, such that there is exactly one simple path between any two vertices. 学校网站放的中文的但我不想补Latex。 直接模拟就可以，一个小技巧，就是把每个节点的子节点按照给定的BFS序排序，再模拟即可。 12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758596061626364656667686970717273747576777879#include&lt;bits/stdc++.h&gt;using namespace std;int n;vector&lt;int&gt; e[200006];int a[200005],id[200005];int ans[200005];bool vis[200005];int cn;bool cmp(int x,int y){ return id[x]&lt;id[y];}void bfs(int s){ queue&lt;int&gt; q; vis[s]=1; q.push(s); while(!q.empty()) { int u=q.front(); q.pop(); ans[++cn]=u; for(auto v:e[u]) { if(vis[v]) { continue; } vis[v]=1; q.push(v); } } }int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;n; for(int i=1;i&lt;n;i++) { int x,y; cin&gt;&gt;x&gt;&gt;y; e[x].push_back(y); e[y].push_back(x); } for(int i=1;i&lt;=n;i++) { cin&gt;&gt;a[i]; id[a[i]]=i; } for(int i=1;i&lt;=n;i++) { sort(e[i].begin(),e[i].end(),cmp);; } bfs(1); for(int i=1;i&lt;=n;i++) { if(ans[i]!=a[i]) { cout&lt;&lt;&quot;No
&quot;; return 0; } } cout&lt;&lt;&quot;Yes
&quot;; return 0;} D. 构造图：唯一出边 给定一个 $N$ 个点 $M$ 条边的无向图，保证没有重边和自环。 要求你给每一条边确定一个方向，生成一张有向图，使得这张有向图上的每一个点都有且只有一条出边。 输出所有可行的方案数，答案对 $998244353$ 取模。 只有一条出边说明边数和结点数相等，就得到一个基环树森林（其实并不重要） 只需要判断对于每一个联通图是否是基环树森林，如果是，答案为 $2^N$ ，否则为0 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566#include&lt;bits/stdc++.h&gt;using namespace std;const int mod=998244353;int n,m;vector&lt;int&gt; e[200005];bool vis[200005];int cnt,ans=1;void dfs(int u,int par){ vis[u]=1; for(auto v:e[u]) { if(v==par) { continue; } if(vis[v]) { cnt++; } else { dfs(v,u); } }}int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;n&gt;&gt;m; for(int i=0;i&lt;m;i++) { int u,v; cin&gt;&gt;u&gt;&gt;v; e[u].push_back(v); e[v].push_back(u); } for(int i=1;i&lt;=n;i++) { if(!vis[i]) { cnt=0; dfs(i,0); if(cnt==2) { (ans*=2)%=mod; } else { ans=0; } } } cout&lt;&lt;ans&lt;&lt;&quot;
&quot;; return 0;} E. 扫雷 小A玩的扫雷游戏规则是这样的：$n$ 个地雷排成一排，必须从 $1$ 到 $n$ 依次扫过。扫一个雷需要花费 $1$ 秒 的时间，如果成功排除当前雷，则可以排除下一个雷；否则的话地雷就会引爆，游戏失败，还需要从头开始重新扫雷。扫完第 $n$ 个雷后才会胜利，游戏结束。 因为小A太弱了，他并不会推断每个位置的雷，只能凭运气去扫雷，所以对于第 $i (1≤i≤n)$ 个雷，他有 ${a_i/b_i}$ 的概率能排除成功，否则雷就会爆炸，要重新开始。 现在小A想知道作为非酋，他游戏胜利的期望用时是多少，你能帮帮可怜的他吗？ zc老师讲了3种做法： 1. $$dp[i]=a_i/b_i*(dp[i+1]+1)+(1-a_i/b_i)*(dp[1]+1)$$ $dp[i]$ 表示从 $i$ 开始拆地雷的期望游戏结束时间。 使用递推的方式将所有的 $dp[i]$ 都用 $dp[1]$ 表示出来，直到得出 $dp[1]=k*dp[1]+b$ 2. $$dp[i]=a_i/b_i+(1-a_i/b_i)*(1+dp[1]+dp[2]+…+dp[i])$$ 12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849#include&lt;bits/stdc++.h&gt;using namespace std;long long qpow(long long a,long long n){ long long ans=1; while(n) { if(n&amp;1) { ans*=a; ans%=mod; } a*=a; a%=mod; n&gt;&gt;=1; } return ans;}long long n;long long p[100005],dp[100005];long long ans;int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;n; for(long long i=0;i&lt;n;i++) { long long a,b; cin&gt;&gt;a&gt;&gt;b; p[i]=qpow(b,mod-2)*a%mod; } ans=dp[0]=qpow(p[0],mod-2); for(long long i=1;i&lt;n;i++) { dp[i]=((ans+1)*(1+mod-p[i])%mod+p[i])%mod*qpow(p[i],mod-2)%mod; ans=(ans+dp[i])%mod; } cout&lt;&lt;ans&lt;&lt;&quot;
&quot;; return 0;} $dp[i] $ 表示从第 $i$ 个到第 $i+1$ 个需要的期望步数，要么直接成功，要么就重新开始，因此再从头加一遍 设 $p_i=a_i/b_i$ $$dp[i]=(dp[i-1]+1)*\sum_{k=1}^{∞}kp_i(1−p_i)^{k−1}= rac{dp[i−1]+1}{p_i}=a_i^{-1}b_i(dp[i−1]+1)$$ 1234567891011121314151617181920212223242526272829303132333435363738394041424344#include&lt;bits/stdc++.h&gt;using namespace std;const int mod=1e9+7;long long n;long long qpow(long long a,long long b){ long long ans=1; while(b) { if(b&amp;1) { ans=ans*a%mod; } a=a*a%mod; b&gt;&gt;=1; } return ans%mod;}long long ans;int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;n; while(n--) { long long a,b; cin&gt;&gt;a&gt;&gt;b; ans++; ans=ans*b%mod*qpow(a,mod-2)%mod; } cout&lt;&lt;ans&lt;&lt;&quot;
&quot;; return 0;} To be continued…
